simple.shipping_method:
def generate_shipping_method(row, col_name):
    import random
    methods = ['standard', 'express', 'overnight', 'pickup']
    return random.choice(methods)

simple.total_amount:
def generate_total_amount(row, col_name):
    import random
    return round(random.uniform(10.0, 5000.0), 2)
